```class Solution {
public:
    int countPairs(vector<int>& nums, int low, int high) {
        int count = 0;
        unordered_map<int, int> freq;
        for (int num : nums) {
            freq[num] = (freq.find(num) == freq.end()) ? 1 : freq[num] + 1;
        }
        for (int num : freq) {
            if (freq.find(num ^ low) != freq.end()) {
                count += freq[num] * freq[num ^ low];
            }
            if (freq.find(num ^ high) != freq.end()) {
                count += freq[num] * freq[num ^ high];
            }
        }
        return count;
    }
};```
